public PixelBuffer[] ProcessMultiImpl(PixelBuffer?[] inputs, IReadOnlyDictionary<string, object> parameters, PixelGraphContext context)
{
    var input = inputs.Length > 0 && inputs[0] != null ? inputs[0]! :
        new PixelBuffer(context.TileSize, context.TileSize);
    var size = context.TileSize;

    // Compute statistics
    var analysis = Analyze(input, size);

    // Encode each float as a 1x1 PixelBuffer (value stored in R channel)
    var results = new PixelBuffer[7];
    for (var i = 0; i < 6; i++)
    {
        results[i] = new PixelBuffer(1, 1);
        results[i].SetPixel(0, 0, analysis[i], analysis[i], analysis[i], 1f);
    }
    results[6] = input; // Passthrough image

    return results;
}

private static float[] Analyze(PixelBuffer buffer, int size)
{
    var pixels = size * size;
    var sumLum = 0f;
    var sumSat = 0f;
    var histogram = new float[256];
    var edgeCount = 0;
    float dominantHue = 0f;
    var hueHistogram = new float[360];

    // Sobel kernels
    var sobelX = new[,] { { -1, 0, 1 }, { -2, 0, 2 }, { -1, 0, 1 } };
    var sobelY = new[,] { { -1, -2, -1 }, { 0, 0, 0 }, { 1, 2, 1 } };

    for (var y = 0; y < size; y++)
    {
        for (var x = 0; x < size; x++)
        {
            var (r, g, b, _) = buffer.GetPixel(x, y);
            var lum = r * 0.299f + g * 0.587f + b * 0.114f;
            sumLum += lum;

            // Saturation
            var maxC = MathF.Max(r, MathF.Max(g, b));
            var minC = MathF.Min(r, MathF.Min(g, b));
            sumSat += maxC > 0f ? (maxC - minC) / maxC : 0f;

            // Luminance histogram
            var bin = (int)(lum * 255f);
            bin = Math.Clamp(bin, 0, 255);
            histogram[bin]++;

            // Hue histogram
            var hue = 0f;
            if (maxC - minC > 0.01f)
            {
                var delta = maxC - minC;
                if (maxC == r) hue = 60f * (((g - b) / delta) % 6f);
                else if (maxC == g) hue = 60f * (((b - r) / delta) + 2f);
                else hue = 60f * (((r - g) / delta) + 4f);
                if (hue < 0) hue += 360f;
            }
            var hueBin = (int)(hue % 360);
            hueHistogram[hueBin]++;
        }
    }

    // Edge detection (sampled for performance)
    var step = Math.Max(1, size / 32);
    for (var y = step; y < size - step; y += step)
    {
        for (var x = step; x < size - step; x += step)
        {
            float gx = 0, gy = 0;
            for (var ky = -1; ky <= 1; ky++)
            {
                for (var kx = -1; kx <= 1; kx++)
                {
                    var (r, g, b, _) = buffer.GetPixel(x + kx, y + ky);
                    var val = r * 0.299f + g * 0.587f + b * 0.114f;
                    gx += val * sobelX[ky + 1, kx + 1];
                    gy += val * sobelY[ky + 1, kx + 1];
                }
            }
            if (MathF.Sqrt(gx * gx + gy * gy) > 0.3f) edgeCount++;
        }
    }

    var avgLum = sumLum / pixels;

    // Contrast = standard deviation of luminance
    var sumDiff = 0f;
    for (var y = 0; y < size; y++)
    {
        for (var x = 0; x < size; x++)
        {
            var (r, g, b, _) = buffer.GetPixel(x, y);
            var lum = r * 0.299f + g * 0.587f + b * 0.114f;
            sumDiff += (lum - avgLum) * (lum - avgLum);
        }
    }
    var contrast = MathF.Sqrt(sumDiff / pixels);

    // Entropy from histogram
    var entropy = 0f;
    for (var i = 0; i < 256; i++)
    {
        if (histogram[i] > 0f)
        {
            var p = histogram[i] / pixels;
            entropy -= p * MathF.Log(p, 2);
        }
    }
    entropy /= 8f; // Normalize to [0,1]

    // Dominant hue
    var maxHueCount = 0;
    for (var i = 0; i < 360; i++)
    {
        if (hueHistogram[i] > maxHueCount)
        {
            maxHueCount = (int)hueHistogram[i];
            dominantHue = i / 360f;
        }
    }

    // Edge density
    var totalSamples = ((size - 2 * step) / step) * ((size - 2 * step) / step);
    var edgeDensity = totalSamples > 0 ? edgeCount / (float)totalSamples : 0f;
    var avgSat = sumSat / pixels;

    return new[] { avgLum, contrast, entropy, edgeDensity, dominantHue, avgSat };
    }
